      "code": "def normalize_scores(scores: list[int]) -> list[float] {
    max_score: int = 0;
    for score in scores {
        if score > max_score {
            max_score = score;
        }
    }

    scaled: list[float] = [];
    for score in scores {
        if max_score == 0 {
            scaled.append(0.0);
        } else {
            scaled.append((score * 100.0) / max_score);
        }
    }
    return scaled;
}

with entry {
    print(normalize_scores([10, 25, 50]));
}",
