      "code": "node Job {
    has name: str;
    has duration: int;

    def finish_time(start_time: int) -> int {
        return start_time + self.duration;
    }
}

edge DependsOn {
    has note: str = "required before next job";
}

walker ScheduleStats {
    has total_duration: int = 0;
    has longest_job: int = 0;

    def record(duration: int) -> int {
        self.total_duration = self.total_duration + duration;
        if duration > self.longest_job {
            self.longest_job = duration;
        }
        return self.total_duration;
    }
}

def buffered_duration(durations: list[int], buffer: int) -> int {
    total: int = 0;
    for duration in durations {
        total = total + duration + buffer;
    }
    return total;
}

